/**
 * @file vfft_calibration.h
 * @brief Hardware calibration data — walk thresholds and IL crossovers
 *
 * Generated by bench_walk and bench_il, consumed by the planner.
 * One file per hardware, persists across runs.
 *
 * Format (vfft_calibration.txt):
 *   # VectorFFT hardware calibration
 *   # L1d: 49152 bytes (48 KB)
 *   # ISA: AVX2
 *   walk  8 128        # R=8:  walk wins at K>=128
 *   walk 32  32        # R=32: walk wins at K>=32
 *   walk 64   0        # R=64: walk never wins (0 = disabled)
 *   il    5 512        # R=5:  IL wins at K>=512
 *   il    7 256        # R=7:  IL wins at K>=256
 *   il    8 1024       # R=8:  IL wins at K>=1024
 */

#ifndef VFFT_CALIBRATION_H
#define VFFT_CALIBRATION_H

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#ifndef VFFT_MAX_RADIX
#define VFFT_MAX_RADIX 130
#endif

typedef struct {
    size_t walk_threshold[VFFT_MAX_RADIX];  /* K where walk starts winning (0 = never) */
    size_t il_crossover[VFFT_MAX_RADIX];    /* K where IL starts winning (0 = never) */
    int    loaded;                           /* 1 if loaded from file */
} vfft_calibration;

static inline void vfft_calibration_init(vfft_calibration *cal)
{
    memset(cal, 0, sizeof(*cal));
}

/* ═══════════════════════════════════════════════════════════════
 * LOAD
 * ═══════════════════════════════════════════════════════════════ */

static inline int vfft_calibration_load(vfft_calibration *cal, const char *path)
{
    FILE *f = fopen(path, "r");
    if (!f) return -1;

    char line[256];
    while (fgets(line, sizeof(line), f)) {
        /* Skip comments and empty lines */
        if (line[0] == '#' || line[0] == '\n' || line[0] == '\r') continue;

        char type[16];
        size_t radix, threshold;
        if (sscanf(line, "%15s %zu %zu", type, &radix, &threshold) == 3) {
            if (radix < VFFT_MAX_RADIX) {
                if (strcmp(type, "walk") == 0) {
                    cal->walk_threshold[radix] = threshold;
                } else if (strcmp(type, "il") == 0) {
                    cal->il_crossover[radix] = threshold;
                }
            }
        }
    }

    fclose(f);
    cal->loaded = 1;
    return 0;
}

/* ═══════════════════════════════════════════════════════════════
 * SAVE
 * ═══════════════════════════════════════════════════════════════ */

static inline int vfft_calibration_save(const vfft_calibration *cal,
                                         const char *path,
                                         size_t l1d_bytes,
                                         const char *isa_name)
{
    FILE *f = fopen(path, "w");
    if (!f) return -1;

    fprintf(f, "# VectorFFT hardware calibration\n");
    fprintf(f, "# L1d: %zu bytes (%zu KB)\n", l1d_bytes, l1d_bytes / 1024);
    fprintf(f, "# ISA: %s\n", isa_name ? isa_name : "unknown");
    fprintf(f, "# Format: type radix threshold_K\n");
    fprintf(f, "#   walk R K  — use block-walk for radix R when K >= threshold\n");
    fprintf(f, "#   il   R K  — use interleaved codelet for radix R when K >= threshold\n");
    fprintf(f, "#   0 = feature disabled for this radix\n\n");

    /* Walk thresholds */
    fprintf(f, "# Walk thresholds (generated by bench_walk)\n");
    for (size_t r = 2; r < VFFT_MAX_RADIX; r++) {
        if (cal->walk_threshold[r] > 0) {
            fprintf(f, "walk %3zu %5zu\n", r, cal->walk_threshold[r]);
        }
    }

    fprintf(f, "\n# IL crossovers (generated by bench_il)\n");
    for (size_t r = 2; r < VFFT_MAX_RADIX; r++) {
        if (cal->il_crossover[r] > 0) {
            fprintf(f, "il   %3zu %5zu\n", r, cal->il_crossover[r]);
        }
    }

    fclose(f);
    return 0;
}

/* ═══════════════════════════════════════════════════════════════
 * PRINT
 * ═══════════════════════════════════════════════════════════════ */

static inline void vfft_calibration_print(const vfft_calibration *cal)
{
    printf("  Calibration: %s\n", cal->loaded ? "loaded" : "defaults");

    int any_walk = 0, any_il = 0;
    for (size_t r = 2; r < VFFT_MAX_RADIX; r++) {
        if (cal->walk_threshold[r] > 0) {
            if (!any_walk) { printf("  Walk thresholds:\n"); any_walk = 1; }
            printf("    R=%-3zu  K >= %zu\n", r, cal->walk_threshold[r]);
        }
    }
    if (!any_walk) printf("  Walk: disabled (no calibration)\n");

    for (size_t r = 2; r < VFFT_MAX_RADIX; r++) {
        if (cal->il_crossover[r] > 0) {
            if (!any_il) { printf("  IL crossovers:\n"); any_il = 1; }
            printf("    R=%-3zu  K >= %zu\n", r, cal->il_crossover[r]);
        }
    }
    if (!any_il) printf("  IL: disabled (no calibration)\n");
}

/* ═══════════════════════════════════════════════════════════════
 * QUERY — used by planner at plan creation time
 * ═══════════════════════════════════════════════════════════════ */

static inline int vfft_calibration_should_walk(
    const vfft_calibration *cal, size_t R, size_t K)
{
    if (!cal || !cal->loaded) return 0;
    if (R >= VFFT_MAX_RADIX) return 0;
    size_t thresh = cal->walk_threshold[R];
    return (thresh > 0 && K >= thresh) ? 1 : 0;
}

static inline int vfft_calibration_should_il(
    const vfft_calibration *cal, size_t R, size_t K)
{
    if (!cal || !cal->loaded) return 0;
    if (R >= VFFT_MAX_RADIX) return 0;
    size_t thresh = cal->il_crossover[R];
    return (thresh > 0 && K >= thresh) ? 1 : 0;
}

#endif /* VFFT_CALIBRATION_H */
